// isValidIdentifier checks if a string is a valid JavaScript identifier
// and prevents access to dangerous properties like __proto__, constructor, prototype
func isValidIdentifier(s string) bool {
	if len(s) == 0 {
		return false
	}

	// Block dangerous property names that could lead to prototype pollution
	dangerousNames := map[string]bool{
		"__proto__":   true,
		"constructor": true,
		"prototype":   true,
		"eval":        true,
		"Function":    true,
	}

	if dangerousNames[s] {
		return false
	}

	// First character must be letter, underscore, or dollar sign
	first := s[0]
	if !((first >= 'a' && first <= 'z') || (first >= 'A' && first <= 'Z') || first == '_' || first == '$') {
		return false
	}

	// Remaining characters can be letters, digits, underscores, or dollar signs
	for i := 1; i < len(s); i++ {
		c := s[i]
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '_' || c == '$') {
			return false
		}
	}

	return true
}

