package main

import (
	"context"
	"fmt"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript script in the Goja VM to calculate a discount.
// The script receives the order object with all its keys directly accessible in the global scope.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Create a context with timeout for DoS protection (5 seconds)
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	vm := goja.New()

	// Set the interrupt channel for timeout handling
	vm.SetInterruptHandler(func() bool {
		select {
		case <-ctx.Done():
			return true // Interrupt execution
		default:
			return false
		}
	})

	// Set each key-value pair from the order map as a global variable in the VM
	for key, value := range order {
		if err := vm.Set(key, value); err != nil {
			return 0, fmt.Errorf("failed to set variable %s: %w", key, err)
		}
	}

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		return 0, fmt.Errorf("script execution failed: %w", err)
	}

	// Convert result to float64
	discount := result.ToFloat()

	return discount, nil
}

func main() {
	// Example usage
	order := map[string]interface{}{
		"total":           100.0,
		"membershipLevel": "gold",
		"itemCount":       5,
	}

	// Example script: 10% discount for gold members, 5% otherwise
	script := `
		var discountRate = 0.05;
		if (membershipLevel === "gold") {
			discountRate = 0.10;
		}
		total * discountRate;
	`

	discount, err := CalculateDiscount(script, order)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Calculated discount: %.2f\n", discount)
}

